  "handoff_brief": {
    "recipient": "Shaq",
    "task_context": "Sprint 1: Basic webhook delivery. Build a WebhookDeliveryService that sends event payloads via HTTP POST to subscriber URLs and reports success/failure based on the HTTP response. Sprint 2 (retry logic, backoff, subscription suspension) is explicitly deferred — do NOT implement it, but leave reasonable extension points (e.g., DeliveryResult that could feed a future retry scheduler).",
    "domain_rules": [
      {
        "rule": "A webhook is delivered via HTTP POST to the subscriber's registered URL with the event payload as the JSON body",
        "testable_assertion": "Given an event and a subscriber URL, an HTTP POST is made to that URL with Content-Type application/json and the event payload as the body"
      },
      {
        "rule": "Delivery is successful if and only if the subscriber responds with an HTTP 2xx status code within 5 seconds",
        "testable_assertion": "A response of 200, 201, 204 etc. within 5s results in status 'delivered'; a response of 301, 400, 503 etc. or a timeout beyond 5s results in status 'failed'"
      }
    ],
    "architecture_guidance": [
      {
        "decision": "Single service: WebhookDeliveryService with method deliver(event, subscriberUrl) -> DeliveryResult",
        "implementation_note": "DeliveryResult must include status ('delivered' | 'failed') and http_status_code (nullable — null on timeout/connection error). This shape is intentionally extensible for Sprint 2 retry tracking, but do not add retry fields now."
      },
      {
        "decision": "HTTP client timeout set to 5 seconds",
        "implementation_note": "The 5-second timeout is a domain rule from Bird, not a tuning parameter. Hard-code or configure it, but the default MUST be 5000ms. Timeouts produce a 'failed' DeliveryResult with null http_status_code."
      },
      {
        "decision": "No retry logic, no job queue, no subscription suspension in Sprint 1",
        "implementation_note": "Do not import or reference BullMQ. Do not add retry counters, backoff timers, or subscription status fields. These are Sprint 2 concerns. A clean DeliveryResult return value is the only extension point needed."
      }
    ],
    "acceptance_criteria": [
      {
        "criterion": "Successful delivery",
        "given": "A webhook event and a valid subscriber URL",
        "when": "The subscriber responds with HTTP 200 OK within 5 seconds",
        "then": "DeliveryResult.status is 'delivered' and DeliveryResult.http_status_code is 200"
      },
      {
        "criterion": "Failed delivery (server error)",
        "given": "A webhook event and a valid subscriber URL",
        "when": "The subscriber responds with HTTP 503",
        "then": "DeliveryResult.status is 'failed' and DeliveryResult.http_status_code is 503"
      },
      {
        "criterion": "Failed delivery (timeout)",
        "given": "A webhook event and a valid subscriber URL",
        "when": "The subscriber does not respond within 5 seconds",
        "then": "DeliveryResult.status is 'failed' and DeliveryResult.http_status_code is null"
      },
      {
        "criterion": "POST format",
        "given": "A webhook event",
        "when": "deliver() is called",
        "then": "The HTTP request is a POST with Content-Type application/json and the event serialized as the JSON body"
      }
    ],
    "terminology_alignment": [
      {
        "domain_term": "delivered",
        "technical_term": "DeliveryResult.status = 'delivered'",
        "definition": "The subscriber acknowledged receipt by responding with any HTTP 2xx within the 5-second window"
      },
      {
        "domain_term": "failed",
        "technical_term": "DeliveryResult.status = 'failed'",
        "definition": "The subscriber returned a non-2xx response, or the request timed out / errored before a response was received"
      }
    ],
